var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"이 시체의 흔적…","JPN":"死体にあるこの痕……","ENG":"The traces of this corpse...","TWN":"這具屍體的痕跡……"},"stage":{"bg":"FLOOR_01","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"침식체에게 공격받은 게 아니야. 총에 맞았어.","JPN":"これは侵食体に襲われた傷じゃない。銃で撃たれている。","ENG":"He wasn't attacked by a C.O. He was shot.","TWN":"沒有受到過侵蝕體的攻擊。他是被槍打中的。"},"stage":{"bg":"FLOOR_01","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"즉사는 아니지만 살아남긴 어려운 상처였겠지.","JPN":"即死ではなかったけれど、傷のせいで亡くなったんだ。","ENG":"A deadly wound, but he didn't die instantly.","TWN":"雖然不是一槍斃命，但造成的傷口讓他很難活下來。"},"stage":{"bg":"FLOOR_01","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그렇다면 자기 죽음을 준비할 시간이 있었을 테고…","JPN":"ということは、死ぬまでに何かを残す時間があったはず……","ENG":"That means he had time to prepare for his death...","TWN":"這樣一來，他就有時間為自己的死亡做好準備了……"},"stage":{"bg":"FLOOR_01","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"찾았다. 탐사용 블랙박스야.","JPN":"見つけた。探査用のブラックボックス。","ENG":"There it is. The exploration black box.","TWN":"找到了。探索用的黑盒。"},"stage":{"bg":"FLOOR_01","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"셰퍼드. 이런 걸 발견했는데, 내가 좀 재생해봐도…","JPN":"シェパード、こんなものを見つけたんだけど、再生してみてもいいか？","ENG":"Shepherd? I found this. Can I play it–","TWN":"牧羊犬。我發現了這個的東西，可以讓我播放一下……"},"stage":{"bg":"FLOOR_01","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"코오…","JPN":"グー……","ENG":"Zzz...","TWN":"呼嚕嚕……"},"stage":{"bg":"FLOOR_01","slots":{"L":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_PRIDE"},"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"잠든 건가?","JPN":"眠ったのか？","ENG":"Is she asleep?","TWN":"睡著了嗎？"},"stage":{"bg":"FLOOR_01","slots":{"L":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_PRIDE"},"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"날 경계하는 줄 알았는데. 편하게 늘어졌네.","JPN":"ぐっすり眠っている。私を警戒していると思ってたのに。","ENG":"I thought she was keeping an eye on me. But she's passed out so comfortably.","TWN":"還以為會對我很警惕。睡得還真香。"},"stage":{"bg":"FLOOR_01","slots":{"L":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_PRIDE"},"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"차라리 잘 됐어.","JPN":"ちょうどよかった。","ENG":"Maybe it's better this way.","TWN":"這樣也好。"},"stage":{"bg":"FLOOR_01","slots":{"L":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_PRIDE"},"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"됐다…!","JPN":"よし、できた……！","ENG":"Done...!","TWN":"好了……！"},"stage":{"bg":"FLOOR_01","slots":{"L":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"후욱… 후…","JPN":"はぁ……はぁ……","ENG":"*Huff* *Huff...*","TWN":"呼……呼……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_CAMERA","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"총이라는 거 정말 아프군. 자주 맞긴 힘들겠어.","JPN":"銃ってのは本当に痛いな。撃たれてはじめてわかった。","ENG":"Gun shots sting, eh? Remind me not to get shot often.","TWN":"被槍打中還真痛，一天到晚被打中會很難過。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_CAMERA","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"모르핀을 챙겨와서 천만다행이네.","JPN":"モルヒネがあってよかった。","ENG":"Thank god I brought some morphine.","TWN":"謝天謝地我還帶了一些嗎啡。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_CAMERA","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"아, 참고로 모르핀은 이게 마지막이야. 내 시체를 뒤져봐야 헛수고일 테니 미리 말해두지.","JPN":"あ、ちなみにモルヒネはこれで最後だ。俺の死体を漁ったところでないからな、予め言っておく。","ENG":"Oh, but just so you know, this is the last of it. So you don't need to rummage through my corpse.","TWN":"啊，這是最後的量了。我提前告訴你，免得到時候還要來搜一遍我的屍體。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_CAMERA","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"이런 곳까지 와서 내 시체의 블랙박스를 뒤지는 녀석이 누군진 모르겠지만… 당신을 보낸 게 북방합의체라면, 찾는 건 여기에 없을 거야.","JPN":"こんな場所まで来て、僕の死体のブラックボックスを漁るなんて、どんなやつかは知らないが……もし君が北方合意体と関係しているなら、お望みのものはここにはない。","ENG":"I don't know who's even going to find my black box all the way here, but... if the Northern Union sent you, then what you're looking for isn't here.","TWN":"雖然不知道會是誰，千里迢迢來到這裡回收我屍體上的黑盒……但如果是北方和議會派你來的，那麼你我勸你少白費功夫。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_CAMERA","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"그쪽이 찾는 건 내가 진작에 안전한 곳으로 빼돌렸거든. 하하.","JPN":"君が探しているものは、すでに僕が安全な場所に移しておいたんだ。はは。","ENG":"I've already hid it someplace safe a long time ago. Haha.","TWN":"你們要找的東西，我很早之前就已經藏到了安全的地方。哈哈。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_CAMERA","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"이 목소린…?","JPN":"この声は……？","ENG":"This voice...","TWN":"這個聲音是……？"},"stage":{"bg":"FLOOR_01","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"에드윈…?","JPN":"エッドウィン……？","ENG":"Edwin...?","TWN":"艾德溫……？"},"stage":{"bg":"FLOOR_01","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_EXOSUIT","text":{"KOREA":"여긴 인간이 감히 상대할 수 없는 괴물들투성이야. 당신보다 먼저 온 녀석들도 전부 끔찍하게 당했지.","JPN":"ここには人間の力ではどうすることもできない化け物が大量にいる。君より先にたどり着いた連中も、全員悲惨な最後を迎えた。","ENG":"This place is flooded with monsters that humans can't defeat. The people who came here before you have all met horrific deaths.","TWN":"這裡到處都是人類對付不了的怪物。你們之前的那幾批人也都經歷了十分可怕的遭遇。"},"stage":{"bg":"FLOOR_01","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_EXOSUIT","text":{"KOREA":"이걸 듣고 있다면, 빨리 여기서 도망쳐.","JPN":"これを聞いているなら、今すぐ逃げた方がいい。","ENG":"If you're listening to this right now, get the hell out of here.","TWN":"如果你聽到這裡，就趕緊給我離開。"},"stage":{"bg":"FLOOR_01","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"정말 당신이야?","JPN":"本当に……あなたなの？","ENG":"Is that really you?","TWN":"真的是你嗎？"},"stage":{"bg":"FLOOR_01","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"왜…","JPN":"どうして……","ENG":"Why...","TWN":"為什麼……"},"stage":{"bg":"FLOOR_01","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"당신이 왜 여기에 있어?","JPN":"どうしてあなたがこんなところにいるんだ。","ENG":"Why are you here?","TWN":"為什麼你會在這裡？"},"stage":{"bg":"FLOOR_01","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};